// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "警局的冷氣太強了。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪坐在受理台前的塑膠椅上，包包放在膝上，手放在包包側袋的拉鏈上——那裡面裝著那面小鏡子。她不知道為什麼要帶著它出門，只是出門前最後一刻把它塞了進去。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）第七天了。再問一次。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她已經來過三次。每次都是同樣的問題，每次得到的答案都差不多。但她還是來了，像她還是會走進悠真的房間一樣——明知道推不開，還是要伸手。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "朝倉小姐，悠真的案子我們還在調查中。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "受理台後的警員翻開一個資料夾，語氣平穩，像在唸一份寫好的進度報告。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "目前沒有勒索電話，也沒有提款異常，帳戶沒有被動過。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "悠真手機在失蹤第二天傳出一則訊息，內容是「想冷靜幾天」，發送位置在東京灣岸方向。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪的手指在拉鏈上收緊了一下。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "車站監視器拍到他自己刷卡進站、獨自搭車，沒有人跟在旁邊。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "學校那邊也回報了，悠真最近睡眠不太穩定，精神壓力比較大，導師有找他談過。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "研究中心的部分我們聯繫過了，對方文件齊全，配合調查，目前沒有明確的犯罪跡象。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "警員停了一下，把資料夾翻到下一頁。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "另外——朝倉小姐，妳不是悠真法律上的監護人，完整的調查資料我們沒辦法對妳公開，這部分請妳理解。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "目前優先調查方向，還是自願離家，或者被網路上認識的人帶走，這兩個可能。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "每一句都很有禮貌。每一句都沒有說錯。每一句合在一起，就是把門關上。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪沒有立刻回話。她盯著受理台上那疊空白表格，心裡把警方說的話和她知道的東西擺在一起，一條一條對。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）自願離家。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）悠真沒帶備用眼鏡。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）他出門一定會帶備用眼鏡盒。七天了，那個盒子還在桌角。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）他沒帶常用充電器。那條線他走到哪帶到哪，因為手機電池老舊。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）漫畫盒裡塞的零用錢也沒拿。他知道那裡有錢。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）遊戲帳號沒登出。他連睡覺都掛著。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把這些東西在心裡排成一列，像證物桌上擺開的物件。每一件都很小，小到警方不會當一回事。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他如果真的想離家，至少會刪掉搜尋紀錄。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）他很怕被我罵。每次借我手機都會先清一遍。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這些不是能讓警方立刻改方向的證據。澪知道。一個沒帶眼鏡盒的中學生，在程序上不能證明任何事。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但這些加在一起，足以讓她知道——「自願離家」這四個字，不對。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "那些訊息和監視器畫面，你們有查過來源嗎？", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "我們有確認過，訊息是從悠真自己的手機發出的，監視器畫面也經過比對。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "他沒帶備用眼鏡，沒帶充電器，零用錢也沒拿，遊戲帳號還掛著。要離家的人不會這樣。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "朝倉小姐，我們理解妳的心情。但目前這些都只是生活習慣的推測，證明不了什麼。我們會繼續調查。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "又是有禮貌。又是沒有說錯。又是門沒有開。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪張了張嘴，沒有再說。她知道在這裡吵沒有用——上一次來的時候她把同樣的話講了兩遍，對方用同樣的語氣回了她兩遍。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她低下頭，手伸進包包側袋，碰到那面小鏡子的塑膠邊緣。她握了一下，又鬆開，拿出手機，想再確認一次悠真最後定位的截圖。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲從走廊那頭過來，停在她旁邊。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪抬頭。一個穿深色西裝的男人站在那裡，領帶鬆著，臉上有很深的疲態。她沒見過這個人——不是前幾次接待她的那個。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "男人看了一眼受理台後的警員，又看了一眼澪，視線在她放在台面的手機上掃過，然後——停了一下。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看的是她包包側袋露出來的那面小鏡子。半截塑膠邊緣從拉鏈縫裡露出來，褪色的卡通圖案朝上。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "停頓很短。短到澪差點以為是自己看錯。然後那個男人把視線收回去，像什麼都沒發生。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "妳是朝倉源一郎的女兒。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪愣了一下。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯你認識我爸？", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "以前共事過。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有多說。澪的父親朝倉源一郎是舊刑警，幾年前失蹤，法律狀態到現在都沒有完全理清。她不常提這件事，提了也沒有人接得住。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "妳父親以前也以為⋯⋯只要查清楚就夠了。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這句話像嘲諷，又像別的什麼。澪聽不出來，只覺得胃裡沉了一下。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯這句話是什麼意思。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "沒什麼。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉頭看了一眼受理台後的警員，警員對他點了個頭，像他們之間有什麼不需要講的默契。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "研究中心那邊，不要一個人去。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯為什麼？", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "不要一個人去。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有解釋。說完就走了，腳步聲往走廊深處去，沒有回頭。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪坐在原處，手裡還握著手機。受理台後的警員看了她一眼，把一張新的受理單推過來。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "朝倉小姐，如果妳有新的具體線索，可以填這張，我們會列入調查。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著那張空白單子。她已經填過三張了。每一張都列了同樣的東西，每一張都沒有下文。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）每個人說的都有道理。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）沒有勒索，沒有暴力，訊息是他自己發的，監視器拍到他自己走的，研究中心文件齊全，我不是監護人。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）每一步都對。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）合在一起，就是沒有人要找他。", background: Background.Chapter_1_Ch1_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把單子抽過來，沒有填，折好放進口袋。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "冷氣還在吹。她站起來的時候，包包側袋的拉鏈鬆了一點，那面小鏡子的邊緣又露出來。她伸手把它推回去，拉上拉鏈。", background: Background.Chapter_1_Ch1_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個男人剛才看鏡子的那一眼，她記住了。不是因為他看見了什麼——是因為他自己好像也不確定，自己為什麼要看。", background: Background.Chapter_1_Ch1_Act3_S0 },
];
